"""Filesystem 100% em memória — sandbox segura para ilustrar infecção."""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Iterable
import hashlib


@dataclass
class VNode:
    path: str
    content: str = ""
    kind: str = "file"  # file | dir
    tags: set[str] = field(default_factory=set)
    infected: bool = False


class VirtualFileSystem:
    """Árvore virtual: nenhum arquivo real do SO é tocado."""

    def __init__(self) -> None:
        self.nodes: dict[str, VNode] = {}
        self.mkdir("/")

    def mkdir(self, path: str) -> None:
        path = self._norm(path)
        self.nodes[path] = VNode(path=path, kind="dir")

    def write(self, path: str, content: str, tags: Iterable[str] | None = None) -> VNode:
        path = self._norm(path)
        parent = "/".join(path.split("/")[:-1]) or "/"
        if parent not in self.nodes:
            self.mkdir(parent)
        node = VNode(path=path, content=content, kind="file", tags=set(tags or []))
        self.nodes[path] = node
        return node

    def read(self, path: str) -> str:
        return self.nodes[self._norm(path)].content

    def exists(self, path: str) -> bool:
        return self._norm(path) in self.nodes

    def list_files(self, prefix: str = "/") -> list[VNode]:
        prefix = self._norm(prefix)
        return [
            n
            for p, n in sorted(self.nodes.items())
            if n.kind == "file" and (prefix == "/" or p.startswith(prefix.rstrip("/") + "/") or p == prefix)
        ]

    def mark_infected(self, path: str, marker: str = "# INFECTED-MARKER\n") -> None:
        node = self.nodes[self._norm(path)]
        if not node.infected:
            node.content = marker + node.content
            node.infected = True
            node.tags.add("infected")

    def sha256(self, path: str) -> str:
        data = self.read(path).encode("utf-8")
        return hashlib.sha256(data).hexdigest()

    def tree(self) -> str:
        lines = ["VIRTUAL FS"]
        for path, node in sorted(self.nodes.items()):
            if path == "/":
                continue
            flag = " [INFECTED]" if node.infected else ""
            kind = "📁" if node.kind == "dir" else "📄"
            lines.append(f"  {kind} {path}{flag}")
        return "\n".join(lines)

    @staticmethod
    def _norm(path: str) -> str:
        path = path.replace("\\", "/")
        if not path.startswith("/"):
            path = "/" + path
        if len(path) > 1 and path.endswith("/"):
            path = path[:-1]
        return path

    @classmethod
    def demo_host(cls) -> "VirtualFileSystem":
        """Host fictício com pastas e programas 'saudáveis'."""
        vfs = cls()
        for d in ("/home/user", "/home/user/docs", "/opt/apps", "/tmp", "/etc"):
            vfs.mkdir(d)
