        vfs.write("/opt/apps/editor.py", "print('editor ok')\n", tags={"app", "python"})
        vfs.write("/opt/apps/backup.py", "print('backup ok')\n", tags={"app", "python"})
        vfs.write("/etc/hosts", "127.0.0.1 localhost\n", tags={"config"})
        return vfs

