#!/usr/bin/env python3
"""
Lab 09 — Scanner estilo YARA (regras textuais simples).

Procura marcadores educacionais no VFS / strings conhecidas.
"""

from __future__ import annotations

import re
import sys
from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]
sys.path.insert(0, str(ROOT))

from common import VirtualFileSystem, print_banner

RULES = [
    {
        "name": "DZ_Edu_Virus_Marker",
        "pattern": r"DZ-EDU-VIRUS-MARKER",
        "meta": "Marcador educacional de infecção de arquivo",
    },
    {
        "name": "DZ_Ransom_Note",
        "pattern": r"README_RESCUE|arquivos virtuais foram",
        "meta": "Nota de resgate fictícia",
    },
    {
        "name": "DZ_Locked_Ext",
        "pattern": r"\.locked\.sim",
        "meta": "Extensão ilustrativa de ransomware",
    },
]


def scan_vfs(vfs: VirtualFileSystem) -> list[dict]:
    hits = []
    for node in vfs.list_files():
        blob = node.path + "\n" + node.content
        for rule in RULES:
            if re.search(rule["pattern"], blob, flags=re.IGNORECASE):
                hits.append(
                    {
                        "rule": rule["name"],
                        "path": node.path,
                        "meta": rule["meta"],
                    }
                )
    return hits


def main() -> None:
    print_banner("09 · Scanner estilo YARA")
    vfs = VirtualFileSystem.demo_host()
    # Injeta artefatos educacionais
    vfs.mark_infected("/opt/apps/editor.py", "# DZ-EDU-VIRUS-MARKER\n")
    vfs.write("/home/user/docs/notes.txt.locked.sim", "00ff", tags={"locked"})
    vfs.write("/home/user/docs/README_RESCUE.txt", "SIMULAÇÃO: arquivos virtuais foram bloqueados.\n")

    hits = scan_vfs(vfs)
    if not hits:
        print("Nenhuma regra casou.")
    for h in hits:
        print(f"  [MATCH] {h['rule']} @ {h['path']} — {h['meta']}")
    print(f"\nTotal: {len(hits)} matches")


if __name__ == "__main__":
    main()
